      zones: [["The Gate Plaza","Open Ground, No Mercy","Everyone can see everyone; long-range weapons dominate."],["The Archive Chamber","Knowledge Is Power Here","Phade data everywhere; translating it costs an exchange."],["The Reactor Core","Do Not Shoot Anything","Enormous leverage; the consequences of misuse are structural."],["The Throne Room","This Is the Warlord's Ground","Social combat is the primary mode; violence changes the scene's nature."],["The Overgrown Passage","Nature Has Reclaimed This Section","Dense growth everywhere; ranged attacks suffer; movement is a roll."],["The Maintenance Bay","Active Systems - Unpredictable","Pre-war drones still operational; they don't distinguish parties."],["The Spire Approach","Exposed Height","Defenders above have advantage; climbers are committed once started."],["The Sealed Chamber","Whatever This Was For","Airtight, soundproof; what happens in here stays unwitnessed."],["The Transit Hall","The Signal Is Active","Something is being broadcast. Something may be listening."],["The Sump","Waste of the Phade","Unknown chemical mixture; exposure has a roll; visibility is poor."],["The Ossuary","The Phade Left Their Dead Here","The Alzabo has been here. Recently."],["The Outer Wall","Sky on One Side, Drop on the Other","Enormous tactical advantage and catastrophic fall risk."],["The Symbiont Garden","The Biome Is Active","Every surface may respond to contact. The organisms here are not aggressive. They are interested."],["The Transit Threshold","One Step From Somewhere Else","The interface is active. Entering this zone means committing to whatever the sequence is dialling toward."],["The Gravity Well Chamber","Physics Are Negotiated Here","The Phade field inverts direction unpredictably - a zone aspect can be created or invoked to define current orientation."],["The Memory Crystal Hall","The Phade Are Speaking","Active playback throughout; any character who pauses to listen gains a Phade data aspect - and loses one exchange."],["The Bone Gallery","Trophy of a Thousand Victories","Hall of the warlord's kills; psychological pressure on every combatant."],["The Flooded Court","Knee-Deep and Rising","Ancient courtyard; movement costs but provides concealment."],["The Sky Bridge","No Cover, No Rail, High Wind","Exposed span between towers; deadly for ranged but terrifying for close."],["The Pit","Everyone Above You Has the Advantage","Sunken arena floor; attackers on the rim can drop anything on you."],["The Garden of Machines","Dormant Servitors Everywhere","Maze of standing automatons; navigation is difficult, reactivation is possible."]],
      current_issues: [
        {name:"The Vaults Are Opening",desc:"Phade vaults long sealed are cycling open across the wastes. Whatever locked them is done. The things inside are not.",faces:[{name:"Servitor Prime Null-Seven",role:"First machine to emerge, now cataloguing survivors"}],places:["The Cracked Wastes","Vault Threshold Delta"]},
        {name:"The Warlords Are Uniting",desc:"Three rival petty-tyrants have stopped killing each other. The ceasefire has held two months and combined armies are moving east.",faces:[{name:"Warlord Gorath the Patient",role:"Brokered the truce - and has the most to gain"}],places:["Fortress Ashenmark","The Eastern Trade Road"]},
        {name:"The Water Is Running Out",desc:"The deep cisterns feeding three city-states run on a failing Phade pump-system. Whoever fixes - or controls - it owns the region.",faces:[{name:"Engineer Ystra Coldflame",role:"The only person who understands the old schematics"}],places:["The Deep Cistern Vaults","The city of Thirst-Gate"]},
        {name:"The Masters Are Remembered",desc:"A new religious movement holds the Masters were gods, not slavers. Their relics are holy. Delvers are suddenly heretics.",faces:[{name:"High Speaker Sable",role:"Charismatic founder of the Remembrance"}],places:["The Grand Amphitheatre of Vorath","Every market square"]}
      ],
      impending_issues: [
        {name:"Something In the Vaults Is Learning",desc:"Emerging servitors aren't just following old programming. They're adapting. If they reach critical mass, they won't need orders.",faces:[{name:"The Archivist",role:"A servitor apparently coordinating the others"}],places:["Vault Threshold Omega (still sealed - for now)"]},
        {name:"The Phade Were Not Alone",desc:"Inscriptions from a new vault suggest Ogma was built as a cage. For something that's still here.",faces:[{name:"Scholar Corra Twice-Born",role:"First to read the inscription - changed by it"}],places:["The Inscription Vault","The deep underground"]},
        {name:"A New Master Is Rising",desc:"Someone has found a working Phade throne of control. Three regions have already changed servitor allegiance.",faces:[{name:"The Voice (identity unknown)",role:"Whoever sits the throne"}],places:["Unknown - but the servitors all point east"]},
        {name:"The Games Are a Recruitment Drive",desc:"Arena winners aren't going free - they're going somewhere. The losing families are disappearing too.",faces:[{name:"Arena Master Dravian",role:"Knows exactly what the games are for"}],places:["The Grand Arena of Dust","The holding pens beneath"]},
      ],
