      challenge_types: [
        {name: "Vault Breach", desc: "Break into a Phade structure before the security sequence completes", primary: "Athletics or Crafts", opposing: "The vault's automated response - Notice and Physique checks to resist", success: "Access secured; interior revealed", failure: "Locked out - or locked in with an active guardian"},
        {name: "Arena Survival", desc: "Last long enough in the arena to make a deal, not win the fight", primary: "Fight or Provoke", opposing: "Escalating crowd pressure and increasingly dangerous opponents", success: "Deal made; reputation intact or improved", failure: "Forced to full combat - or worse, the crowd turns hostile"},
        {name: "Wasteland Crossing", desc: "Get the group across dangerous terrain before supplies or conditions fail", primary: "Athletics and Lore", opposing: "Cumulative environmental stress - each failure costs supplies or health", success: "Arrive intact with enough left to operate", failure: "Arrive compromised - injuries, lost gear, or wrong destination"},
        {name: "Warlord Negotiation", desc: "Get a concession from a warlord who holds all the obvious advantages", primary: "Rapport or Provoke", opposing: "The warlord's pride, lieutenants, and prior commitments", success: "A real concession - territory, hostage, neutrality", failure: "Talks collapse - and now they know what you wanted"},
        {name: "Sky-Chase", desc: "Pursue or evade another skiff across difficult terrain", primary: "Pilot (use Drive) and Shoot", opposing: "The opposing pilot's skill and their craft's characteristics", success: "Forced down or clean escape, as intended", failure: "Crash or capture - the skiff is damaged regardless"},
        {name: "Servitor Network Intrusion", desc: "Inject false commands into a Phade servitor relay before it propagates", primary: "Crafts and Lore", opposing: "The network's own correction protocols - time-limited", success: "The false commands execute; network rerouted", failure: "Triggered an alert - and the correction identified you as the source"},
        {name: "Black Market Acquisition", desc: "Source a specific relic or resource through illegal channels under time pressure", primary: "Contacts and Resources", opposing: "Competing buyers, suspicious sellers, and possible law enforcement", success: "Item acquired at negotiated cost", failure: "Outbid, burned, or flagged by the wrong people"},
        {name: "Settlement Rescue", desc: "Evacuate civilians from a failing settlement before the situation becomes unrecoverable", primary: "Rapport and Athletics", opposing: "Panic, structural failure, and the cause of the evacuation still being present", success: "Majority evacuated; key people safe", failure: "Partial evacuation - the people left behind are the ones who mattered most"},
        {name: "Beast Taming", desc: "Calm, redirect, or outmanoeuvre a territorial beast without lethal force", primary: "Rapport or Physique", opposing: "The beast's fear response - escalating danger as it panics", success: "Beast stands down or is redirected; passage clear", failure: "Full hostile conflict - and now it's alarmed and angry"},
        {name: "Mass Evacuation", desc: "Move a large population through hostile territory before the threat overtakes them", primary: "Rapport and Athletics", opposing: "Terrain, panic, time, and whatever is pursuing them", success: "Population reaches safety mostly intact", failure: "Significant casualties; the party carries that weight forward"},
        {name: "Crowd Negotiation", desc: "Shift the opinion of a hostile crowd away from violence using only words and presence", primary: "Provoke or Rapport", opposing: "The crowd's existing rage and whoever is working to keep it hot", success: "Crowd disperses or redirects; violence averted", failure: "The crowd chooses a target - possibly the party"},
        {name: "Sky Race", desc: "Reach a sky-island, vault, or destination first in a contested open-air sprint", primary: "Athletics and Notice", opposing: "Rival crew's skiff, the terrain, and whatever both parties are racing toward", success: "First to arrive; choice of position", failure: "Second to arrive; the rival has had time to prepare"},
        {name: "Biome Navigation", desc: "Move through a Phade environmental system that is actively operating - not hostile by design, but indifferent to whether the party survives its function", primary: "Lore and Athletics", opposing: "The system's operational logic and the biome's protective organisms responding to perceived interference", success: "Objective reached; system undisturbed; the party now understands something about what it was designed to do", failure: "Objective reached at cost - the system has registered the intrusion and adjusted; what that means will become apparent"},
        {name: "Phade Language Puzzle", desc: "Operate a Phade system using partial translation under time pressure, with incorrect inputs having immediate structural consequences", primary: "Lore and Investigate", opposing: "The incompleteness of available translation and the system's intolerance for input errors", success: "System operates as intended; translation gap is partially closed; the party knows more than when they started", failure: "System operates incorrectly - what it does instead of what was intended is the new problem"},
        {name: "False Prophet Confrontation", desc: "Expose a warlord's false claim to Phade authority in front of the community whose belief sustains that authority", primary: "Rapport and Lore", opposing: "The community's investment in the belief and the prophet's experience managing exactly this kind of challenge", success: "Authority is publicly undermined; the community's response is variable but the claim no longer holds", failure: "Confrontation fails - the community's belief is stronger than the evidence, and the party's credibility in this region is now a problem"},
        {name: "Symbiont Assessment", desc: "Determine the nature, agenda, and integration depth of a Phade organism before it finishes making its own assessment of the party", primary: "Empathy and Lore", opposing: "The organism's non-human reasoning and the difficulty of distinguishing benign integration from strategic infiltration", success: "Nature assessed; integration depth understood; the party can make an informed decision about how to proceed", failure: "Assessment incomplete - a decision must be made with insufficient information, and the organism has been making its own decisions throughout"}
      ],

